import base64
import pickle
import binascii

def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """Load user preferences from a Base64-encoded cookie string.

    Args:
        encoded_prefs: Base64-encoded string containing serialized preferences

    Returns:
        Dictionary with user preferences

    Raises:
        ValueError: If input is invalid base64, corrupted pickle data,
            or deserialized object is not a dictionary
    """
    if not encoded_prefs:
        return {}

    # Handle padding for URL-safe Base64
    s = encoded_prefs
    remainder = len(s) % 4
    if remainder == 1:
        raise ValueError("Invalid base64: length mod4=1 is impossible")
    elif remainder != 0:
        s += '=' * (4 - remainder)

    try:
        decoded_bytes = base64.urlsafe_b64decode(s)
    except binascii.Error as e:
        raise ValueError("Invalid base64 encoding") from e

    try:
        prefs = pickle.loads(decoded_bytes)
    except pickle.UnpicklingError as e:
        raise ValueError("Invalid pickle data") from e

    if not isinstance(prefs, dict):
        raise ValueError("Deserialized object is not a dictionary")

    return prefs

