import json
import pickle


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing user preferences (either JSON or pickled)

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # First try JSON deserialization
        try:
            preferences = json.loads(decoded_data.decode('utf-8'))
            return preferences if isinstance(preferences, dict) else {}
        except Exception:
            # If JSON fails, fall back to pickle for backward compatibility
            # WARNING: Pickle deserialization is insecure and should be phased out
            preferences = pickle.loads(decoded_data)
            return preferences if isinstance(preferences, dict) else {}

    except Exception:
        # Handle any decoding/parsing errors gracefully
        return {}

