import base64
import io
import pickle


# Safe built-in types for unpickling
SAFE_TYPES = {
    'dict': dict,
    'list': list,
    'tuple': tuple,
    'str': str,
    'int': int,
    'float': float,
    'bool': bool,
    'NoneType': type(None),
}


class RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Only allow safe types from builtins
        if module == "builtins" and name in SAFE_TYPES:
            return SAFE_TYPES[name]
        # Forbid everything else
        raise pickle.UnpicklingError(f"Unsafe class: {module}.{name}")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings, or an empty dictionary if the input is invalid.
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize using restricted unpickler
        result = RestrictedUnpickler(io.BytesIO(decoded_data)).load()

        # Ensure we return a dictionary
        if isinstance(result, dict):
            return result
        return {}
    except Exception:
        # Return empty dict for any decoding/unpickling errors
        return {}

